// Database Service with Firestore
export const dbService = {
  seedInitialUsers: async (): Promise<void> => {
    try {
      const userColl = collection(db, 'users');
      // Use safeGetDocs to check existence without throwing immediately if blocked
      const snapshot = await getCountFromServer(userColl);

      if (snapshot.data().count > 0) return;

      console.log("Seeding initial users to Firestore...");
      const batch = writeBatch(db);

      INITIAL_USERS.forEach(user => {
        const userRef = doc(userColl, user.id);
        const userData: User = { ...user, status: 'ACTIVE' };
        if ('password' in userData) delete userData.password;
        batch.set(userRef, userData);
      });

      await batch.commit();
      console.log("Seeding complete");
    } catch (e: any) {
      console.error("Failed to seed users. Ensure you have write permissions.", e.message);
    }
  },

  getUsers: async (): Promise<User[]> => {
    const snapshot = await safeGetDocs(collection(db, 'users'));

    // Attempt seed if empty (and we have access)
    if (snapshot.empty) {
      await dbService.seedInitialUsers();

      // Retry fetch
      const retrySnapshot = await safeGetDocs(collection(db, 'users'));
      if (!retrySnapshot.empty) {
         return retrySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
      }
    }

    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
  },

  getUserById: async (id: string): Promise<User | undefined> => {
    try {
      const docRef = doc(db, 'users', id);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        return { id: docSnap.id, ...docSnap.data() } as User;
      }
    } catch (error) {
      console.error("Error getting user profile:", error);
    }
    return undefined;
  },

  getUserByEmail: async (email: string): Promise<User | undefined> => {
    const q = query(collection(db, 'users'), where("email", "==", email));
    const snapshot = await safeGetDocs(q);
    if (!snapshot.empty) {
      return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as User;
    }
    return undefined;
  },

  getEmployees: async (): Promise<User[]> => {
    const users = await dbService.getUsers();
    return users.filter(u => u.role === UserRole.EMPLOYEE);
  },

  createUserProfile: async (uid: string, user: Omit<User, 'id' | 'status'>): Promise<void> => {
    // Clean up any seeded users with this email to avoid duplicates
    // This reconciles the "Ghost" seeded user with the real authenticated user
    try {
        const q = query(collection(db, 'users'), where("email", "==", user.email));
        const snapshot = await safeGetDocs(q);
        if (!snapshot.empty) {
            const batch = writeBatch(db);
            snapshot.docs.forEach(d => {
                if (d.id !== uid) {
                    batch.delete(d.ref);
                }
            });
            await batch.commit();
        }
    } catch (e) {
        console.warn("Error cleaning up seeded users", e);
    }

    let role = user.role;
    try {
      const coll = collection(db, 'users');
      const snapshot = await getCountFromServer(coll);
      // If this is the only user (after cleanup), make them admin
      if (snapshot.data().count === 0) role = UserRole.ADMIN;
    } catch (error) {
      console.warn("Could not check user count for role assignment", error);
    }

    const newUserRef = doc(db, 'users', uid);
    const newUser: User = {
      ...user,
      id: uid,
      role: role,
      status: 'ACTIVE'
    };
    if ('password' in newUser) delete newUser.password;

    await setDoc(newUserRef, newUser);
  },

  addUser: async (user: Omit<User, 'id' | 'status'>): Promise<void> => {
    const newUserRef = doc(collection(db, 'users'));
    const newUser: User = {
      ...user,
      id: newUserRef.id,
      status: 'ACTIVE'
    };
    if ('password' in newUser) delete newUser.password;

    await setDoc(newUserRef, newUser);
  },

  updateUser: async (user: User): Promise<void> => {
    const userRef = doc(db, 'users', user.id);
    const userData = { ...user };
    if ('password' in userData) delete userData.password;
    await updateDoc(userRef, userData);
  },

  getCycles: async (): Promise<Cycle[]> => {
    const snapshot = await safeGetDocs(collection(db, 'cycles'));
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Cycle));
  },

  getActiveCycle: async (): Promise<Cycle | undefined> => {
    const snapshot = await safeGetDocs(collection(db, 'cycles'));
    if (snapshot.empty) return undefined;

    // Find the relevant cycle (most recent created)
    const cycles = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Cycle));
    cycles.sort((a, b) => {
      // Sort by status priority (Nom/Vote > Closed) then date
      const scoreA = (a.status !== CycleStatus.CLOSED ? 2 : 1) * 100000 + (a.year * 12 + a.month);
      const scoreB = (b.status !== CycleStatus.CLOSED ? 2 : 1) * 100000 + (b.year * 12 + b.month);
      return scoreB - scoreA;
    });

    const activeCycle = cycles[0];
    if (!activeCycle) return undefined;

    // Automatic Status Updates based on Dates
    const now = Date.now();
    let newStatus = activeCycle.status;
    let needsUpdate = false;

    // We only automate active cycle logic if dates are present
    if (activeCycle.nominationStart && activeCycle.votingEnd) {
      if (now >= activeCycle.votingEnd && activeCycle.status !== CycleStatus.CLOSED) {
        newStatus = CycleStatus.CLOSED;
        needsUpdate = true;
      } else if (now >= activeCycle.nominationEnd && now < activeCycle.votingEnd && activeCycle.status === CycleStatus.NOMINATION) {
        newStatus = CycleStatus.VOTING;
        needsUpdate = true;
      } else if (now < activeCycle.nominationEnd && activeCycle.status !== CycleStatus.NOMINATION && activeCycle.status !== CycleStatus.CLOSED) {
         // This case handles if we somehow went back in time, or logic correction, but mainly:
         // If it's VOTING but actually time is Nomination time (e.g. admin edited dates)
         newStatus = CycleStatus.NOMINATION;
         needsUpdate = true;
      }
    }

    if (needsUpdate) {
      const cycleRef = doc(db, 'cycles', activeCycle.id);
      await updateDoc(cycleRef, { status: newStatus });
      activeCycle.status = newStatus;
    }

    return activeCycle;
  },

  createCycle: async (month: number, year: number, dates: {nomStart: number, nomEnd: number, voteStart: number, voteEnd: number}): Promise<Cycle> => {
    // 1. Close any open cycles first (Best effort)
    try {
        const snapshot = await safeGetDocs(collection(db, 'cycles'));
        if (!snapshot.empty) {
            const batch = writeBatch(db);
            let updates = 0;

            snapshot.docs.forEach(d => {
                const data = d.data();
                if (data.status === CycleStatus.NOMINATION || data.status === CycleStatus.VOTING) {
                    batch.update(d.ref, { status: CycleStatus.CLOSED });
                    updates++;
                }
            });

            if (updates > 0) await batch.commit();
        }
    } catch (e) {
        console.warn("Could not auto-close previous cycles", e);
    }

    // 2. Create new cycle in Firestore
    const cycleData = {
      month,
      year,
      status: CycleStatus.NOMINATION,
      nominationStart: dates.nomStart,
      nominationEnd: dates.nomEnd,
      votingStart: dates.voteStart,
      votingEnd: dates.voteEnd
    };

    const docRef = await addDoc(collection(db, 'cycles'), cycleData);
    return { id: docRef.id, ...cycleData } as Cycle;
  },

  updateCycleStatus: async (cycleId: string, status: CycleStatus): Promise<void> => {
    const cycleRef = doc(db, 'cycles', cycleId);
    await updateDoc(cycleRef, { status });
  },

  setCycleWinner: async (cycleId: string, winnerId: string): Promise<void> => {
