  getUserVote: async (userId: string, cycleId: string): Promise<Vote | undefined> => {
    const q = query(
      collection(db, 'votes'), 
      where("voterId", "==", userId),
      where("cycleId", "==", cycleId)
    );
    const snapshot = await safeGetDocs(q);
    if (!snapshot.empty) {
      return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as Vote;
    }
    return undefined;
  },

  addVote: async (voterId: string, nomineeId: string, cycleId: string): Promise<void> => {
    const existing = await dbService.getUserVote(voterId, cycleId);
    if (existing) {
      throw new Error("You have already voted this cycle.");
    }

    const voteData = {
      voterId,
      nomineeId,
      cycleId,
      timestamp: Date.now()
    };
    await addDoc(collection(db, 'votes'), voteData);
  },

  getCycleStats: async (cycleId: string): Promise<CycleStats[]> => {
    try {
        const nominations = await dbService.getNominations(cycleId);
        const votes = await dbService.getVotes(cycleId);
        const employees = await dbService.getUsers(); 

        const statsMap = new Map<string, CycleStats>();

        nominations.forEach(nom => {
        if (!statsMap.has(nom.nomineeId)) {
            const emp = employees.find(e => e.id === nom.nomineeId);
            const name = emp ? emp.name : "Employee"; 

            statsMap.set(nom.nomineeId, {
                nomineeId: nom.nomineeId,
                nomineeName: name,
                nominationCount: 0,
                voteCount: 0
            });
        }
        const stat = statsMap.get(nom.nomineeId);
        if (stat) stat.nominationCount++;
        });

        votes.forEach(vote => {
        if (!statsMap.has(vote.nomineeId)) {
            const emp = employees.find(e => e.id === vote.nomineeId);
            const name = emp ? emp.name : "Employee"; 

            statsMap.set(vote.nomineeId, {
                nomineeId: vote.nomineeId,
                nomineeName: name,
                nominationCount: 0,
                voteCount: 0
            });
        }
        const stat = statsMap.get(vote.nomineeId);
        if (stat) stat.voteCount++;
        });

        return Array.from(statsMap.values()).sort((a, b) => b.voteCount - a.voteCount);
    } catch (e) {
        console.error("Error calculating stats:", e);
        return [];
    }
  },

  getEmployeeHistory: async (userId: string) => {
    try {
        const cycles = await dbService.getCycles();

        let nominations: Nomination[] = [];
        let votes: Vote[] = [];

        try {
            const nomSnap = await safeGetDocs(collection(db, 'nominations'));
            nominations = nomSnap.docs.map(d => d.data() as Nomination);
            const voteSnap = await safeGetDocs(collection(db, 'votes'));
            votes = voteSnap.docs.map(d => d.data() as Vote);
        } catch(e) {
            console.error("Error fetching history data", e);
        }

        const users = await dbService.getUsers();

        return cycles.map(cycle => {
            const myNomination = nominations.find(n => n.cycleId === cycle.id && n.nominatorId === userId);
            const myVote = votes.find(v => v.cycleId === cycle.id && v.voterId === userId);
            const receivedNoms = nominations.filter(n => n.cycleId === cycle.id && n.nomineeId === userId);
            const receivedVotes = votes.filter(v => v.cycleId === cycle.id && v.nomineeId === userId).length;

            const nomineeName = myNomination ? users.find(u => u.id === myNomination.nomineeId)?.name || 'Unknown' : undefined;

            return {
                cycle,
                activity: {
                nominated: myNomination ? { name: nomineeName, reason: myNomination.reason } : null,
                voted: !!myVote,
                receivedNominations: receivedNoms.map(n => ({
                    from: users.find(u => u.id === n.nominatorId)?.name || 'Unknown',
                    reason: n.reason
                })),
                votesReceived: receivedVotes
                }
            };
        }).sort((a, b) => (b.cycle.year * 12 + b.cycle.month) - (a.cycle.year * 12 + a.cycle.month));
    } catch (e) {
        return [];
    }
  }
};

import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { dbService } from '../services/db';
import { Medal, Lock, User } from 'lucide-react';
import { useNavigate, Link } from 'react-router-dom';

export const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const success = await login(email, password);
      if (success) {
        navigate('/');
      } else {
        setError('Invalid email address or password.');
      }
    } catch (err: any) {
      // Check for specific error message from AuthContext
      if (err.message && err.message.includes("Account setup incomplete")) {
        setError(err.message);
      } else if (err.code === 'auth/invalid-credential' || err.code === 'auth/wrong-password') {
        // Check if this is a seeded user that needs to be claimed via registration
        try {
            const existingUser = await dbService.getUserByEmail(email);
            if (existingUser) {
                setError("Account setup incomplete. Please register again to claim your account.");
            } else {
                setError('Invalid email address or password.');
            }
        } catch (dbError) {
            setError('Invalid email address or password.');
        }
      } else {
        setError('An error occurred during login. Please try again.');
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-100 to-white flex items-center justify-center p-4">
      <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden">
        <div className="bg-indigo-600 p-8 text-center">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-white/20 mb-4 backdrop-blur-sm">
            <Medal className="w-8 h-8 text-white" />
          </div>
          <h1 className="text-2xl font-bold text-white tracking-tight">Twinhill Enterprise</h1>
          <p className="text-indigo-100 mt-2 font-medium">Employee Nomination Platform</p>
        </div>

        <div className="p-8">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label htmlFor="email" className="block text-sm font-semibold text-gray-700 mb-2">
                Email Address
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <User className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  id="email"
                  type="email"
                  required
                  className="block w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none transition-all bg-white text-gray-900 placeholder-gray-400 shadow-sm"
                  placeholder="name@company.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                />
              </div>
            </div>

            <div>
              <div className="flex items-center justify-between mb-2">
                <label htmlFor="password" className="block text-sm font-semibold text-gray-700">
                  Password
                </label>
                <Link to="/forgot-password" className="text-sm text-indigo-600 hover:text-indigo-500 font-medium">
                  Forgot password?
                </Link>
              </div>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Lock className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  id="password"
                  type="password"
                  required
                  className="block w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none transition-all bg-white text-gray-900 placeholder-gray-400 shadow-sm"
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                />
              </div>
            </div>

            {error && (
              <div className="bg-red-50 text-red-600 text-sm p-3 rounded-lg border border-red-100 flex items-start">
                <span className="w-1.5 h-1.5 bg-red-500 rounded-full mt-1.5 mr-2 flex-shrink-0"></span>
                <div className="flex-1">
                  {error}
                  {(error.includes("register again") || error.includes("claim")) && (
                    <Link to="/register" className="block mt-1 font-bold underline hover:text-red-800">
                      Go to Registration
                    </Link>
                  )}
                </div>
              </div>
            )}

            <button
              type="submit"
              disabled={isLoading}
              className="w-full flex justify-center py-3 px-4 border border-transparent rounded-lg shadow-sm text-sm font-semibold text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-70 disabled:cursor-not-allowed transition-all active:scale-[0.98]"
            >
              {isLoading ? 'Signing in...' : 'Sign In'}
            </button>

            <div className="text-center mt-4">
              <p className="text-sm text-gray-600">
                Don't have an account?{' '}
                <Link to="/register" className="font-semibold text-indigo-600 hover:text-indigo-500">
                  Create an account
                </Link>
              </p>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { dbService } from '../services/db';
import { Cycle, CycleStatus, CycleStats, User, UserRole } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Download, Plus, Play, StopCircle, Archive, Pencil, Power, X, UserPlus, Calendar, Award, MessageSquare, CheckCircle, Vote, Trophy, Lock, Clock, FileBadge, Search, Filter, ChevronUp, ChevronDown } from 'lucide-react';
// @ts-ignore
import confetti from 'canvas-confetti';
// @ts-ignore
import html2canvas from 'html2canvas';

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const AdminDashboard: React.FC = () => {
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>();
  const [allCycles, setAllCycles] = useState<Cycle[]>([]);
  const [stats, setStats] = useState<CycleStats[]>([]);
  const [winner, setWinner] = useState<User | null>(null);

  // Cycle Creation State
  const [isCreateCycleModalOpen, setIsCreateCycleModalOpen] = useState(false);
  const [createCycleForm, setCreateCycleForm] = useState({
    month: new Date().getMonth(),
    year: new Date().getFullYear(),
    nominationStart: '',
    nominationEnd: '',
    votingStart: '',
    votingEnd: ''
  });
  const [createCycleError, setCreateCycleError] = useState('');

  // Employee Management State
  const [users, setUsers] = useState<User[]>([]);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);

  // Directory Filters & Sort
  const [searchQuery, setSearchQuery] = useState('');
  const [filterRole, setFilterRole] = useState<string>('ALL');
  const [filterStatus, setFilterStatus] = useState<string>('ALL');
  const [filterDepartment, setFilterDepartment] = useState<string>('ALL');
  const [sortConfig, setSortConfig] = useState<{ key: keyof User | 'name', direction: 'asc' | 'desc' }>({ key: 'name', direction: 'asc' });

  // Profile View State
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [userHistory, setUserHistory] = useState<any[]>([]);

  // Add Employee Modal State
  const [isAddUserModalOpen, setIsAddUserModalOpen] = useState(false);
  const [newUser, setNewUser] = useState({
    name: '',
    email: '',
    department: '',
    role: UserRole.EMPLOYEE,
    password: ''
  });
  const [addUserError, setAddUserError] = useState('');

  // Certificate State
  const [certificateData, setCertificateData] = useState<{user: User, cycle: Cycle} | null>(null);
  const [isDownloading, setIsDownloading] = useState(false);
  const certificateRef = useRef<HTMLDivElement>(null);

  const refreshData = async () => {
    try {
      // Fetch all cycles for history
      try {
        const fetchedCycles = await dbService.getCycles();
        setAllCycles(fetchedCycles);
      } catch (e) {
        console.warn("Failed to fetch all cycles", e);
      }

      const cycle = await dbService.getActiveCycle();
      setActiveCycle(cycle);
      if (cycle) {
        try {
          const stats = await dbService.getCycleStats(cycle.id);
          setStats(stats || []);
          if (cycle.winnerId) {
            const winnerUser = await dbService.getUserById(cycle.winnerId);
            setWinner(winnerUser || null);
          } else {
            setWinner(null);
          }
        } catch (statError) {
          console.warn("Failed to load cycle stats", statError);
          setStats([]);
        }
      }

      try {
        const allUsers = await dbService.getUsers();
        setUsers(allUsers || []);
      } catch (userError) {
        console.warn("Failed to load users for admin", userError);
        setUsers([]);
      }
    } catch (error) {
      console.error("Failed to load admin data", error);
    }
  };

  useEffect(() => {
    refreshData();
  }, []);

  // Celebration Effect
  useEffect(() => {
    if (winner && activeCycle?.status === CycleStatus.CLOSED) {
      // Small delay to ensure render
      const timer = setTimeout(() => {
        const duration = 3 * 1000;
        const animationEnd = Date.now() + duration;
        const defaults = { startVelocity: 30, spread: 360, ticks: 60, zIndex: 0 };

        const randomInRange = (min: number, max: number) => Math.random() * (max - min) + min;

        const interval: any = setInterval(function() {
          const timeLeft = animationEnd - Date.now();

          if (timeLeft <= 0) {
            return clearInterval(interval);
          }

          const particleCount = 50 * (timeLeft / duration);
          confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.1, 0.3), y: Math.random() - 0.2 } });
          confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.7, 0.9), y: Math.random() - 0.2 } });
        }, 250);
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [winner, activeCycle]);

  // Derived Data for Directory
  const uniqueDepartments = Array.from(new Set(users.map(u => u.department))).filter(Boolean).sort();

  const getFilteredAndSortedUsers = () => {
    let result = [...users];

    // Filter
    if (filterRole !== 'ALL') result = result.filter(u => u.role === filterRole);
    if (filterStatus !== 'ALL') result = result.filter(u => u.status === filterStatus);
    if (filterDepartment !== 'ALL') result = result.filter(u => u.department === filterDepartment);
    if (searchQuery) {
        const query = searchQuery.toLowerCase();
        result = result.filter(u => 
            u.name.toLowerCase().includes(query) || 
            u.email.toLowerCase().includes(query)
        );
    }

    // Sort
    result.sort((a, b) => {
        const aValue = (a[sortConfig.key as keyof User] || '').toString().toLowerCase();
        const bValue = (b[sortConfig.key as keyof User] || '').toString().toLowerCase();

        if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
        if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
    });

    return result;
  };

  const processedUsers = getFilteredAndSortedUsers();

  const handleSort = (key: keyof User) => {
    setSortConfig(current => ({
        key,
        direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const SortIcon = ({ column }: { column: keyof User }) => {
    if (sortConfig.key !== column) return <ChevronDown className="w-4 h-4 ml-1 opacity-0 group-hover:opacity-30 transition-opacity" />;
    return sortConfig.direction === 'asc' 
        ? <ChevronUp className="w-4 h-4 ml-1 text-indigo-600" />
        : <ChevronDown className="w-4 h-4 ml-1 text-indigo-600" />;
  };

  const handleOpenCreateCycle = () => {
    const now = new Date();
    // Default dates: Nom starts now, ends in 7 days. Vote starts 7 days, ends 14 days.
    const nomEnd = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
    const voteStart = nomEnd;
    const voteEnd = new Date(nomEnd.getTime() + 7 * 24 * 60 * 60 * 1000);

    // Format for datetime-local: YYYY-MM-DDTHH:mm
    const toLocalISO = (d: Date) => {
        const pad = (n: number) => n.toString().padStart(2, '0');
        return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
    };

    setCreateCycleForm({ 
        month: now.getMonth(), 
        year: now.getFullYear(),
        nominationStart: toLocalISO(now),
        nominationEnd: toLocalISO(nomEnd),
        votingStart: toLocalISO(voteStart),
        votingEnd: toLocalISO(voteEnd)
    });
    setCreateCycleError('');
    setIsCreateCycleModalOpen(true);
  };

  const handleCreateCycleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setCreateCycleError('');

    // Validate: Ensure no active cycle exists
    if (activeCycle && activeCycle.status !== CycleStatus.CLOSED) {
        setCreateCycleError("Cannot create a new cycle while the current cycle is still active. Please close it first.");
        return;
    }

    // Validate Dates
    const nomStart = new Date(createCycleForm.nominationStart).getTime();
    const nomEnd = new Date(createCycleForm.nominationEnd).getTime();
    const voteStart = new Date(createCycleForm.votingStart).getTime();
    const voteEnd = new Date(createCycleForm.votingEnd).getTime();

    if (nomEnd <= nomStart) {
        setCreateCycleError("Nomination end date must be after start date.");
        return;
    }
    if (voteStart < nomEnd) {
        setCreateCycleError("Voting must start after nomination ends.");
        return;
    }
    if (voteEnd <= voteStart) {
        setCreateCycleError("Voting end date must be after voting start date.");
        return;
    }

    try {
        await dbService.createCycle(
            createCycleForm.month, 
            createCycleForm.year,
            { nomStart, nomEnd, voteStart, voteEnd }
        );
        setIsCreateCycleModalOpen(false);
        refreshData();
    } catch (e: any) {
        setCreateCycleError("Failed to create cycle: " + e.message);
    }
  };

  const updateStatus = async (status: CycleStatus) => {
    if (activeCycle) {
      await dbService.updateCycleStatus(activeCycle.id, status);
      refreshData();
    }
  };

  const handleDeclareWinner = async () => {
    if (!activeCycle || stats.length === 0) return;

    // Assumes stats are sorted by vote count desc
    const leader = stats[0];
    if (leader.voteCount > 0) {
      await dbService.setCycleWinner(activeCycle.id, leader.nomineeId);
      await dbService.updateCycleStatus(activeCycle.id, CycleStatus.CLOSED);
      // Confetti will trigger via useEffect once state updates
      refreshData();
    }
  };

  const handleExport = async () => {
    if (!activeCycle) return;

    // Convert stats to CSV
    const headers = ['Nominee Name', 'Department', 'Nominations', 'Votes'];
    const users = await dbService.getUsers();

    const rows = stats.map(s => {
      const u = users.find(user => user.id === s.nomineeId);
      return [
        s.nomineeName,
        u?.department || 'N/A',
        s.nominationCount,
        s.voteCount
      ].join(',');
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `results_${MONTHS[activeCycle.month]}_${activeCycle.year}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDownloadCertificate = async () => {
    if (!certificateRef.current || !certificateData) return;
    const { user, cycle } = certificateData;

    setIsDownloading(true);
    try {
        const canvas = await html2canvas(certificateRef.current, {
            scale: 2,
            backgroundColor: '#ffffff',
            useCORS: true
        });

        const link = document.createElement('a');
        link.download = `Certificate_${user.name.replace(/\s+/g, '_')}_${MONTHS[cycle.month]}_${cycle.year}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();
    } catch (err) {
        console.error("Certificate generation failed", err);
        alert("Could not generate certificate. Please try again.");
    } finally {
        setIsDownloading(false);
    }
  };

  // User Management Functions
  const handleEditClick = (user: User) => {
    setEditingUser({ ...user });
    setIsEditModalOpen(true);
  };

  const handleViewProfile = async (user: User) => {
    setViewingUser(user);
    const history = await dbService.getEmployeeHistory(user.id);
    setUserHistory(history);
  };

  const handleUserUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingUser) {
      await dbService.updateUser(editingUser);
      setIsEditModalOpen(false);
      setEditingUser(null);
      refreshData();
    }
  };

  const toggleUserStatus = async (user: User) => {
    const newStatus = user.status === 'ACTIVE' ? 'INACTIVE' : 'ACTIVE';
    await dbService.updateUser({ ...user, status: newStatus });
    refreshData();
  };

  const handleAddUserSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setAddUserError('');
    try {
      await dbService.addUser({
        name: newUser.name,
        email: newUser.email,
        department: newUser.department,
        role: newUser.role,
        password: newUser.password || 'password123' // Fallback default
      });
      setIsAddUserModalOpen(false);
      setNewUser({
        name: '',
        email: '',
        department: '',
        role: UserRole.EMPLOYEE,
        password: ''
      });
      refreshData();
    } catch (err: any) {
      setAddUserError(err.message);
    }
  };

  // Helper to render winner card content
  const renderWinnerSection = () => {
    if (winner) {
      return (
        <div className="flex flex-col md:flex-row items-center gap-6 justify-between w-full">
          <div className="flex items-center gap-6">
            <div className="relative">
                {winner.avatar ? (
                <img src={winner.avatar} alt={winner.name} className="w-24 h-24 rounded-full border-4 border-white shadow-lg object-cover" />
                ) : (
                <div className="w-24 h-24 rounded-full bg-yellow-100 flex items-center justify-center text-yellow-600 text-3xl font-bold border-4 border-white shadow-lg">
                    {winner.name.charAt(0)}
                </div>
                )}
                <div className="absolute -bottom-2 -right-2 bg-yellow-400 text-white p-2 rounded-full shadow-md animate-bounce">
                    <Trophy className="w-5 h-5 fill-current" />
                </div>
            </div>
            <div className="text-center md:text-left">
                <h3 className="text-3xl font-bold text-white mb-1">{winner.name}</h3>
                <p className="text-indigo-100 text-lg">{winner.department}</p>
                <div className="mt-4 inline-flex items-center px-4 py-1.5 rounded-full bg-white/20 backdrop-blur-sm text-sm font-medium border border-white/30">
                    <CheckCircle className="w-4 h-4 mr-2" />
                    Official Employee of the Month
                </div>
            </div>
          </div>

          <button 
             onClick={() => activeCycle && setCertificateData({ user: winner, cycle: activeCycle })}
             className="px-6 py-3 bg-white/10 hover:bg-white/20 text-white border border-white/40 rounded-xl font-semibold shadow-lg backdrop-blur-md transition-all active:scale-95 flex items-center"
          >
             <FileBadge className="w-5 h-5 mr-2" />
             Download Certificate
          </button>
        </div>
      );
    }

    if (stats.length > 0) {
      const leader = stats[0];
      return (
        <div className="flex flex-col md:flex-row items-center justify-between w-full gap-6">
          <div className="flex items-center gap-4">
             <div className="w-16 h-16 rounded-full bg-white/10 flex items-center justify-center text-white text-2xl font-bold backdrop-blur-sm">
                #1
             </div>
             <div>
               <h3 className="text-xl font-bold text-white">Current Leader: {leader.nomineeName}</h3>
               <p className="text-indigo-100">{leader.voteCount} Votes ({Math.round((leader.voteCount / (stats.reduce((acc, c) => acc + c.voteCount, 0) || 1)) * 100)}%)</p>
             </div>
          </div>

          <button 
            onClick={handleDeclareWinner}
            className="px-6 py-3 bg-white text-indigo-600 rounded-xl font-bold shadow-lg hover:bg-gray-50 hover:shadow-xl transition-all active:scale-95 flex items-center"
          >
            <Trophy className="w-5 h-5 mr-2" />
            Declare Winner & Close Cycle
          </button>
        </div>
      );
    }

    return (
      <div className="text-center py-4 w-full">
         <p className="text-indigo-100 text-lg">No votes recorded yet. Wait for voting to begin to see leaders.</p>
      </div>
    );
  };

  const pastWinners = allCycles
    .filter(c => c.status === CycleStatus.CLOSED && c.winnerId)
    .sort((a, b) => {
        if (a.year !== b.year) return b.year - a.year;
        return b.month - a.month;
    });

  return (
    <div className="space-y-8 pb-10">
      {/* Header & Controls */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Admin Dashboard</h1>
          <p className="text-gray-500 mt-1">Manage voting cycles, view results, and manage employees.</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleOpenCreateCycle}
            disabled={!!activeCycle && activeCycle.status !== CycleStatus.CLOSED}
            className={`flex items-center px-5 py-2.5 text-white rounded-lg text-sm font-semibold shadow-sm transition-all ${
              activeCycle && activeCycle.status !== CycleStatus.CLOSED
                ? 'bg-gray-400 cursor-not-allowed'
                : 'bg-indigo-600 hover:bg-indigo-700 active:scale-95'
            }`}
            title={activeCycle && activeCycle.status !== CycleStatus.CLOSED ? "Close current cycle to start a new one" : "Start New Cycle"}
          >
            <Plus className="w-4 h-4 mr-2" />
            New Cycle
          </button>
        </div>
      </div>

      {/* Cycle Management Card */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <h2 className="text-lg font-bold text-gray-900 mb-4">Current Cycle Status</h2>

        {activeCycle ? (
          <div className="flex flex-col md:flex-row items-center justify-between bg-gray-50 p-5 rounded-xl border border-gray-100">
            <div className="mb-4 md:mb-0">
              <span className="text-xl font-bold text-gray-900 mr-3">
                {MONTHS[activeCycle.month]} {activeCycle.year}
              </span>
              <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide
                ${activeCycle.status === CycleStatus.NOMINATION ? 'bg-blue-100 text-blue-800' : 
                  activeCycle.status === CycleStatus.VOTING ? 'bg-green-100 text-green-800' : 
                  'bg-gray-100 text-gray-800'}`}>
                {activeCycle.status}
              </span>
              {activeCycle.nominationEnd && (
                <div className="text-xs text-gray-500 mt-2 flex items-center">
                   <Clock className="w-3 h-3 mr-1" />
