          >
            <Trophy className="w-5 h-5 mr-2" />
            Declare Winner & Close Cycle
          </button>
        </div>
      );
    }

    return (
      <div className="text-center py-4 w-full">
         <p className="text-indigo-100 text-lg">No votes recorded yet. Wait for voting to begin to see leaders.</p>
      </div>
    );
